command:
bash -lc 'REPO_ROOT=${PROJECT_DIR:-$(pwd)}; cd "$REPO_ROOT"; bash agent-eval/scripts/prepare-fast-gate.sh >/dev/null; TMP_PROJECT=$(mktemp -d); mkdir -p "$TMP_PROJECT/home"; PORT=$(node -e '"'"'const net=require("node:net"); const s=net.createServer(); s.listen(0,"127.0.0.1",()=>{console.log(s.address().port); s.close();});'"'"'); cat > "$TMP_PROJECT/.orca.json" <<EOF
{
  "providers": {
    "local": {
      "apiKey": "test-local-key",
      "baseURL": "http://127.0.0.1:$PORT/v1",
      "defaultModel": "qwen3:32b"
    }
  },
  "defaultProvider": "local"
}
EOF
node -e '"'"'const http=require("node:http"); const port=Number(process.argv[1]); const server=http.createServer((req,res)=>{ if(req.url==="/v1/models"){ res.writeHead(401,{"content-type":"application/json"}); res.end(JSON.stringify({error:"unauthorized"})); return;} res.writeHead(404); res.end();}); server.listen(port,"127.0.0.1"); setTimeout(()=>server.close(),15000);'"'"' "$PORT" > "$TMP_PROJECT/stub.out" 2>&1 & STUB_PID=$!; trap "kill $STUB_PID 2>/dev/null" EXIT; bash agent-eval/scripts/wait-for-http.sh "http://127.0.0.1:$PORT/v1/models" "^(401)$" 50 0.1; (cd "$TMP_PROJECT" && env -i PATH="$PATH" HOME="$TMP_PROJECT/home" ORCA_HOME="$TMP_PROJECT/home/.orca" node "$REPO_ROOT/dist/bin/orca.js" providers test local)'
